def _is_within_directory(directory: str, target: str) -> bool:
    """Return True if target is inside directory, resolving symlinks and avoiding traversal."""
    directory = os.path.realpath(directory)
    target = os.path.realpath(target)
    return os.path.commonpath([directory]) == os.path.commonpath([directory, target])

def _safe_tar_filter(member: tarfile.TarInfo, dest_path: str):
    """Filter function to block path traversal and unsafe members."""
    # Construct the absolute target path
    target_path = os.path.join(dest_path, member.name)
    # Normalize to remove any '..' or '.' components
    target_path = os.path.normpath(target_path)
    # Ensure the target stays inside dest_path
    if not _is_within_directory(dest_path, target_path):
        return None  # Skip this member
    # Optionally, restrict to regular files only (like filter='data')
    if not member.isfile():
        return None
    return member

