def extract_tar_to_path(tar_path: str, dest_path: str) -> bool:
    try:
        if not os.path.isfile(tar_path):
            return False
        os.makedirs(dest_path, exist_ok=True)

        def _safe_tar_filter(member: tarfile.TarInfo):
            # Construct the absolute target path
            target_path = os.path.join(dest_path, member.name)
            # Normalize to remove any '..' or '.' components
            target_path = os.path.normpath(target_path)
            # Ensure the target stays inside dest_path
            if not _is_within_directory(dest_path, target_path):
                return None  # Skip this member
            # Optionally, restrict to regular files only (like filter='data')
            if not member.isfile():
                return None
            return member

        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                safe_member = _safe_tar_filter(member)
                if safe_member is None:
                    continue
                tar.extract(member, path=dest_path)
        return True
    except (tarfile.TarError, OSError):
        return False

