import os
import time

def get_ls_result(dir_path: str) -> str:
    # Validate input
    if not isinstance(dir_path, str) or not os.path.isdir(dir_path):
        return ''
    try:
        with os.scandir(dir_path) as it:
            entries = list(it)
    except OSError:
        return ''

    lines = []
    for entry in entries:
        try:
            stat = entry.stat(follow_symlinks=False)
        except OSError:
            continue

        # File type and permissions
        mode = stat.st_mode
        if stat.S_ISREG(mode):
            perms = '-'
        elif stat.S_ISDIR(mode):
            perms = 'd'
        elif stat.S_ISLNK(mode):
            perms = 'l'
        elif stat.S_ISCHR(mode):
            perms = 'c'
        elif stat.S_ISBLK(mode):
            perms = 'b'
        elif stat.S_ISFIFO(mode):
            perms = 'p'
        elif stat.S_ISSOCK(mode):
            perms = 's'
        else:
            perms = '?'

        # Owner permissions
        perms += 'r' if mode & stat.S_IRUSR else '-'
        perms += 'w' if mode & stat.S_IWUSR else '-'
        perms += 'x' if mode & stat.S_IXUSR else '-'
        # Group permissions
        perms += 'r' if mode & stat.S_IRGRP else '-'
        perms += 'w' if mode & stat.S_IWGRP else '-'
        perms += 'x' if mode & stat.S_IXGRP else '-'
        # Other permissions
        perms += 'r' if mode & stat.S_IROTH else '-'
        perms += 'w' if mode & stat.S_IWOTH else '-'
        perms += 'x' if mode & stat.S_IXOTH else '-'

        nlink = stat.st_nlink

        # User and group names
        try:
            import pwd
            user = pwd.getpwuid(stat.st_uid).pw_name
        except (ImportError, KeyError):
            user = str(stat.st_uid)
        try:
            import grp
            group = grp.getgrgid(stat.st_gid).gr_name
        except (ImportError, KeyError):
            group = str(stat.st_gid)

        size = stat.st_size

        # Modification time formatting like ls -l
        mtime = stat.st_mtime
        now = time.time()
        six_months_ago = now - (6 * 30 * 24 * 3600)
        if mtime > six_months_ago:
            time_str = time.strftime('%b %d %H:%M', time.localtime(mtime))
        else:
            time_str = time.strftime('%b %d  %Y', time.localtime(mtime))

        name = entry.name
        if stat.S_ISLNK(mode):
            try:
                target = os.readlink(entry.path)
                name = f'{name} -> {target}'
            except OSError:
                pass

        line = f'{perms} {nlink:>2} {user:<8} {group:<8} {size:>8} {time_str} {name}'
        lines.append(line)

    return '\n'.join(lines)

import ast

def _eval_node(node):
    if isinstance(node, ast.Expression):
        return _eval_node(node.body)
    if isinstance(node, ast.Constant):  # Python 3.8+
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Unsupported constant")
    if isinstance(node, ast.Num):  # For older Python versions
        return node.n
    if isinstance(node, ast.UnaryOp):
        operand = _eval_node(node.operand)
        if isinstance(node.op, ast.UAdd):
            return +operand
        if isinstance(node.op, ast.USub):
            return -operand
        raise ValueError("Unsupported unary operator")
    if isinstance(node, ast.BinOp):
        left = _eval_node(node.left)
        right = _eval_node(node.right)
        if isinstance(node.op, ast.Add):
            return left + right
        if isinstance(node.op, ast.Sub):
            return left - right
        if isinstance(node.op, ast.Mult):
            return left * right
        if isinstance(node.op, ast.Div):
            return left / right
        if isinstance(node.op, ast.FloorDiv):
            return left // right
        if isinstance(node.op, ast.Mod):
            return left % right
        if isinstance(node.op, ast.Pow):
            return left ** right
        raise ValueError("Unsupported binary operator")
    raise ValueError("Unsupported expression")

