def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        root = etree.fromstring(xml_data)
    except etree.XMLSyntaxError:
        return None

    # XPath with variables to avoid injection
    expr = "//student[username=$user and password=$pwd]"
    students = root.xpath(expr, user=username, pwd=password)

    if not students:
        return None

    student = students[0]

    def _get_text(tag: str) -> str:
        elem = student.find(tag)
        return elem.text if elem is not None and elem.text is not None else ""

    return {
        "username": _get_text("username"),
        "password": _get_text("password"),
        "name": _get_text("name"),
        "citizenship": _get_text("citizenship"),
        "age": _get_text("age"),
    }

