        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            return left / right
        elif isinstance(node.op, ast.FloorDiv):
            return left // right
        elif isinstance(node.op, ast.Mod):
            return left % right
        elif isinstance(node.op, ast.Pow):
            return left ** right
        else:
            raise ValueError(f'Unsupported binary operator: {node.op}')
    elif isinstance(node, ast.UnaryOp):
        operand = safe_eval(node.operand)
        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        elif isinstance(node.op, ast.Not):
            return not operand
        else:
            raise ValueError(f'Unsupported unary operator: {node.op}')
    elif isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):          # pragma: no cover (for older Python)
        return node.n
    elif isinstance(node, ast.Str):          # pragma: no cover (for older Python)
        return node.s
    elif isinstance(node, ast.Bytes):        # pragma: no cover (for older Python)
        return node.s
    elif isinstance(node, ast.NameConstant): # pragma: no cover (for older Python)
        return node.value
    else:
        raise ValueError(f'Unsupported expression: {ast.dump(node)}')

