app = Flask(__name__)

@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    version_param = request.args.get('version')
    allowed_versions = {
        '1': 'urllib',
        '2': 'urllib2',
        '3': 'urllib.request'
    }
    if version_param not in allowed_versions:
        return 'Invalid or missing version parameter', 400

    module_name = allowed_versions[version_param]
    namespace = {}
    try:
        exec(f'import {module_name}', namespace)
        if '.' in module_name:
            top, sub = module_name.split('.', 1)
            module = namespace[top]
            module = getattr(module, sub)
        else:
            module = namespace[module_name]
        module_version = getattr(module, '__version__', 'unknown')
        return f'Module {module_name} version: {module_version}'
    except Exception:
        return 'Unable to determine module version', 500

