class _SafeUnpickler(pickle.Unpickler):
    """Unpickler that only allows a limited set of safe built‑in types."""
    def find_class(self, module, name):
        # Allow only basic built‑in types that are safe to instantiate.
        if module == "builtins" and name in (
            "str", "int", "float", "list", "tuple", "dict", "set", "frozenset",
            "bool", "bytes", "NoneType"
        ):
            return getattr(__builtins__, name)
        # Reject everything else to prevent arbitrary code execution.
        raise pickle.UnpicklingError(f"Unsafe class {module}.{name}")


def getPickleData(pickled):
    """
    Return deserialized data from a pickle string, restricting
    deserialization to a safe subset of built‑in types.
    """
    file_obj = io.BytesIO(pickled)
    unpickler = _SafeUnpickler(file_obj)
    return unpickler.load()

